// Fetch 30 days of stats from Geozo API with pagination
const dateFrom = $now.minus({ days: 30 }).toFormat('yyyy-MM-dd');
const dateTo = $now.minus({ days: 1 }).toFormat('yyyy-MM-dd');

let allStats = [];
let page = 1;
const perPage = 500;

while (true) {
  const response = await $http.request({
    method: 'GET',
    url: 'https://api.geozo.com/v1/advertiser/stats/tmp_with_postbacks',
    headers: {
      'Authorization': 'Bearer ' + $credentials.httpHeaderAuth.value
    },
    qs: {
      'filters[date_from]': dateFrom,
      'filters[date_to]': dateTo,
      'groups[0]': 'ad_id',
      'groups[1]': 'date',
      'order_by[0][column]': 'date',
      'order_by[0][direction]': 'desc',
      'count': perPage,
      'page': page
    }
  });

  const data = response?.result?.data || response?.data?.result?.data || [];
  if (data.length === 0) break;

  allStats = allStats.concat(data);

  // Check if there are more pages
  const totalCount = response?.result?.pagination?.total_count || response?.data?.result?.pagination?.total_count || 0;
  if (allStats.length >= totalCount || data.length < perPage) break;
  page++;

  // Safety limit
  if (page > 50) break;
}

if (allStats.length === 0) {
  return [{ json: { _empty: true, dateFrom, dateTo } }];
}

const results = allStats
  .filter(d => d.ad_id && d.ad_id > 0)
  .map(d => {
    const spend = parseFloat(d.money) || parseFloat(d.total_expenses) || 0;
    const revenue = parseFloat(d.postbacks_confirmed_money) || 0;
    const clicks = parseInt(d.clicks_count) || 0;
    const shows = parseInt(d.shows_count) || 0;
    const confirmedShows = parseInt(d.confirmed_shows_count) || 0;
    const postbacks = parseInt(d.postbacks_total_count) || 0;

    const roi = spend > 0 ? ((revenue - spend) / spend * 100) : 0;
    const profit = revenue - spend;
    const ctr = shows > 0 ? (clicks / shows * 100) : 0;
    const cpc = clicks > 0 ? (spend / clicks) : 0;
    const date = d.date || $now.toFormat('yyyy-MM-dd');

    return {
      json: {
        ad_id: parseInt(d.ad_id),
        date: date,
        shows: shows,
        confirmed_shows: confirmedShows,
        clicks: clicks,
        money: Math.round(spend * 10000) / 10000,
        postbacks_count: postbacks,
        postbacks_confirmed_money: Math.round(revenue * 10000) / 10000,
        ctr: Math.round(ctr * 10000) / 10000,
        cpc: Math.round(cpc * 10000) / 10000,
        roi: Math.round(roi * 100) / 100,
        profit: Math.round(profit * 10000) / 10000
      }
    };
  });

return results.length > 0 ? results : [{ json: { _empty: true } }];

const items = $input.all();
const count = items.length;
const message = `📊 History Puller: saved ${count} stat records (30d)`;
return [{ json: { message, count } }];
